const items = $input.all();
const response = items[0].json;
const username = $('Loop Over Items').first().json.instagram_username;

// Apify 에러 또는 빈 응답 체크
if (response.error || response.statusCode >= 400) {
  return [{ json: { _skip: true, _reason: 'apify_error', _username: username } }];
}

// Apify responds with an array even for a single profile
const profile = Array.isArray(response) ? response[0] : response;

// 프로필 없음 (계정 미존재 또는 조회 실패)
if (!profile || !profile.id) {
  return [{ json: { _skip: true, _reason: 'account_not_found', _username: username } }];
}

// 비공개 계정
if (profile.private) {
  return [{ json: { _skip: true, _reason: 'private_account', _username: username } }];
}

// 팔로워 1만 미만
if ((profile.followersCount || 0) < 10000) {
  return [{ json: { _skip: true, _reason: 'insufficient_followers', _username: username } }];
}

// external_url 없음 (공구 링크 페이지 필수)
if (!profile.externalUrl) {
  return [{ json: { _skip: true, _reason: 'no_external_url', _username: username } }];
}

return [{
  json: {
    _skip: false,
    influencer: {
      id: String(profile.id),
      username: profile.username || '',
      full_name: profile.fullName || '',
      biography: profile.biography || '',
      profile_pic_url: profile.profilePicUrlHD || profile.profilePicUrl || '',
      followers_count: profile.followersCount || 0,
      external_url: profile.externalUrl || '',
      external_url_title: (profile.externalUrls && profile.externalUrls[0]) ? profile.externalUrls[0].title : '',
      last_synced_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    },
    latestPosts: profile.latestPosts || [],
    influencer_id: String(profile.id)
  }
}];

const data = $('Profile Mapper').first().json;
const influencerId = data.influencer.id;

// 업로드 성공 여부 확인
const uploadResult = $input.first().json;
const uploadFailed = uploadResult.error || uploadResult.statusCode >= 400;

const storageUrl = uploadFailed
  ? data.influencer.profile_pic_url
  : `https://rcvfnbmiebkfgkevmkhy.supabase.co/storage/v1/object/public/media/influencers/${influencerId}/profile.jpg`;

return [{
  json: {
    ...data,
    influencer: {
      ...data.influencer,
      profile_pic_url: storageUrl,
    },
  },
}];

// Profile Mapper 노드의 출력을 직접 참조
const data = $('Profile Mapper').first().json;
const posts = data.latestPosts || [];
const influencerId = data.influencer_id;
const externalUrl = data.influencer.external_url || '';

// 기존 게시글 ID 조회 결과 참조 (새 게시글만 처리)
const existingResult = $('Postgres - Get Existing Post IDs').first().json;
const existingIds = new Set(existingResult.existing_ids || []);

// 공구 판별 키워드
const STRONG_KEYWORDS = ['공구', '공동구매', '공구오픈', '공구마감', '공구기간', '공구가', '공구링크'];
const COMBO_KEYWORDS = ['오픈', 'open', '마감', '구매', '링크', '프로필', '배송', '선착순', '한정', '할인', '혜택', '이벤트'];

function isGroupBuying(post) {
  const caption = (post.caption || '').toLowerCase();
  const hashtags = (post.hashtags || []).join(' ').toLowerCase();
  const text = caption + ' ' + hashtags;

  for (const kw of STRONG_KEYWORDS) {
    if (text.includes(kw)) return true;
  }

  let comboCount = 0;
  for (const kw of COMBO_KEYWORDS) {
    if (text.includes(kw.toLowerCase())) comboCount++;
    if (comboCount >= 2) return true;
  }
  return false;
}

// SQL 이스케이프 헬퍼
function esc(val) {
  if (val === null || val === undefined) return null;
  return String(val).replace(/'/g, "''");
}

// PostgreSQL 배열 리터럴 변환
  if (!arr || arr.length === 0) return '{}';
  return '{' + arr.map(v => '"' + String(v).replace(/"/g, '\"') + '"').join(',') + '}';
}

const groupBuyingPosts = [];
for (const post of posts) {
  // 이미 DB에 있는 게시글은 스킵
  if (existingIds.has(String(post.id))) continue;

  if (!isGroupBuying(post)) continue;

  groupBuyingPosts.push({
    id: String(post.id),
    influencer_id: influencerId,
    post_url: post.url || '',
    post_type: post.type || '',
    caption: esc(post.caption),
    caption_raw: post.caption || '',
    display_url: post.displayUrl || '',
    external_url: externalUrl,
    posted_at: post.timestamp || null,
    updated_at: new Date().toISOString()
  });
}

if (groupBuyingPosts.length === 0) {
  return [{ json: { _skip: true } }];
}

return groupBuyingPosts.map(p => ({ json: p }));

const items = $input.all();
const year = new Date().getFullYear();

return items.map(item => {
  const caption = item.json.caption_raw || '';

  const body = {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1024,
    messages: [{
      role: 'user',
      content: [
        '다음 인스타그램 공동구매 게시글 캡션에서 상품 정보를 추출해주세요.',
        '',
        '[중요 규칙]',
        '- 반드시 상품 1개만 반환하세요. 게시글에 여러 상품이 있어도 반드시 1개로 합쳐서 반환합니다.',
        '',
        '[product_name 작성 규칙 - 우선순위 순]',
        '1. 세트 판매: 게시글에 명시된 세트명을 그대로 사용',
        '   예) "HaptIQ 햅틱 프라이팬 풀세트 4종" → product_name: "HaptIQ 햅틱 프라이팬 풀세트 4종"',
        '2. 같은 품종의 여러 옵션(사이즈/용량/색상 등): 공통 키워드만 추출',
        '   예) 실리콘 지퍼백 소/중/대, 실리콘 지퍼백 특대 3P → product_name: "실리콘 지퍼백"',
        '   예) 에어팟 케이스 블랙/화이트/베이지 → product_name: "에어팟 케이스"',
        '3. 아예 다른 품종이 혼재: "A + B" 형식으로 병합',
        '   예) 다목적 크림 + 살균제 소독제 → product_name: "다목적 크림 + 살균제 소독제"',
        '',
        '- product_name에서 용량(ml, g, kg, L), 중량, 수량, 개수 등 스펙 정보는 제외하세요.',
        '  예: "살균 스프레이 소독제 대용량 450ml" → "살균 스프레이 소독제"',
        '- 날짜에 시간이 명시되지 않은 경우 반드시 T23:59:59+09:00 (한국 시간)으로 설정하세요.',
        '  예: "3월 8일" → "' + year + '-03-08T23:59:59+09:00". 모든 날짜는 한국 시간(KST, +09:00) 기준입니다.',
        '',
        '[캡션]',
        caption,
        '',
        '[추출 항목]',
        '1. product_name: 위 규칙에 따른 상품명. 찾을 수 없으면 null.',
        '2. price: 공구 가격 (숫자만, 원 단위). 여러 가격이 있으면 가장 대표적인 가격. 찾을 수 없으면 null.',
        '3. category: 상품 카테고리. 다음 중 하나만: "뷰티", "푸드", "패션", "리빙", "키즈", "가전", "여행", "반려동물", "운동/건강", "교육/도서", "문구/취미", "캠핑/레저", "차량용품". 판단 불가 시 null.',
        '4. group_buying_start: 공구 시작 날짜 (ISO 8601, 예: ' + year + '-02-13T00:00:00+09:00). 연도 미명시 시 ' + year + '년 가정. 찾을 수 없으면 null.',
        '5. group_buying_end: 공구 종료 날짜 (ISO 8601). 연도 미명시 시 ' + year + '년 가정. 찾을 수 없으면 null.',
        '6. group_buying_url: 공동구매 링크 URL. 캡션에 URL이 직접 있으면 그 URL. "프로필 링크", "링크는 프로필" 등 프로필 참조 문구가 있으면 "PROFILE_LINK". 둘 다 아니면 null.',
        '',
        '[반환 형식]',
        '반드시 아래 형식의 JSON만 반환하세요. 다른 설명 없이 JSON만 출력하세요.',
        '{ "products": [ { "product_name": "...", "price": ..., "category": "...", "group_buying_start": "...", "group_buying_end": "...", "group_buying_url": "..." } ] }'
      ].join('\n')
    }]
  };

  return {
    json: {
      ...item.json,
      _claudeBody: JSON.stringify(body)
    }
  };
});

const items = $input.all();
const originalItems = $('Prepare Claude Request').all();

function esc(val) {
  if (val === null || val === undefined) return null;
  return String(val).replace(/'/g, "''");
}

function dedupId(influencerId, productName, start, end) {
  const key = `${influencerId}:${productName}:${start}:${end}`;
  let h = 0;
  for (let i = 0; i < key.length; i++) {
    h = ((h << 5) - h + key.charCodeAt(i)) | 0;
  }
  return influencerId + '_' + Math.abs(h).toString(36);
}

const results = [];
for (let i = 0; i < items.length; i++) {
  const claudeResponse = items[i].json;
  const original = originalItems[i].json;

  let products = [];

  try {
    const text = (claudeResponse.content && claudeResponse.content[0] && claudeResponse.content[0].text) || '';
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      if (parsed.products && Array.isArray(parsed.products)) {
        products = parsed.products;
      } else {
        products = [parsed];
      }
    }
  } catch (e) {
    continue;
  }

  for (let p = 0; p < products.length; p++) {
    const prod = products[p];
    const start = prod.group_buying_start || null;
    const end = prod.group_buying_end || null;

    if (!start || !end) continue;

    let url = prod.group_buying_url || null;
    if (url === 'PROFILE_LINK' && original.external_url) {
      url = original.external_url;
    } else if (url === 'PROFILE_LINK') {
      url = null;
    }

    const productName = esc(prod.product_name || null);
    const postId = dedupId(original.influencer_id, productName, start, end);

    results.push({
      json: {
        id: postId,
        influencer_id: original.influencer_id,
        post_url: original.post_url,
        post_type: original.post_type,
        caption: original.caption,
        display_url: original.display_url,
        hashtags_pg: original.hashtags_pg,
        group_buying_start: start,
        group_buying_end: end,
        product_name: productName,
        group_buying_url: url,
        price: prod.price || null,
        category: prod.category || null,
        posted_at: original.posted_at,
        updated_at: original.updated_at
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { _noResults: true } }];
}
return results;

const items = $input.all();
const originalItems = $('IF - Has Display URL').all();

return items.map((uploadItem, i) => {
  const original = originalItems[i].json;
  const uploadJson = uploadItem.json;
  const uploadFailed = !uploadJson || uploadJson.error !== undefined ||
    (uploadJson.statusCode && parseInt(String(uploadJson.statusCode)) >= 400);

  const storageUrl = uploadFailed
    ? original.display_url
    : `https://rcvfnbmiebkfgkevmkhy.supabase.co/storage/v1/object/public/media/posts/${original.id}/display.jpg`;

  return {
    json: {
      ...original,
      display_url: storageUrl,
    }
  };
});
